// ── Button ────────────────────────────────────────────────────────────────────
function Btn({ children, onClick, variant = "primary", style = {}, disabled = false }) {
  const base = {
    width: "100%", padding: "14px 24px", borderRadius: 50, border: "none",
    fontFamily: fonts.body, fontSize: 16, fontWeight: 600, cursor: disabled ? "not-allowed" : "pointer",
    transition: "transform 0.15s, box-shadow 0.15s", display: "flex", alignItems: "center", justifyContent: "center", gap: 8,
  };
  const variants = {
    primary: { background: colors.pink, color: "#fff", boxShadow: "0 4px 16px rgba(242,73,135,0.35)" },
    outline: { background: "transparent", color: colors.blue, border: `2px solid ${colors.blue}` },
    blue: { background: colors.blue, color: "#fff", boxShadow: "0 4px 16px rgba(31,70,152,0.3)" },
    ghost: { background: "rgba(255,255,255,0.6)", color: colors.dark, border: "1.5px solid rgba(0,0,0,0.1)" },
  };
  return (
    <button style={{ ...base, ...variants[variant], ...style, opacity: disabled ? 0.6 : 1 }}
      onClick={onClick} disabled={disabled}
      onMouseEnter={e => { if(!disabled) e.currentTarget.style.transform = "scale(1.02)"; }}
      onMouseLeave={e => { e.currentTarget.style.transform = "scale(1)"; }}>
      {children}
    </button>
  );
}

// ── Input ─────────────────────────────────────────────────────────────────────
function Input({ placeholder, value, onChange, type = "text", style = {} }) {
  const [focused, setFocused] = useState(false);
  return (
    <input
      type={type} placeholder={placeholder} value={value} onChange={onChange}
      onFocus={() => setFocused(true)} onBlur={() => setFocused(false)}
      style={{
        width: "100%", padding: "14px 18px", borderRadius: 16, border: `2px solid ${focused ? colors.pink : "rgba(0,0,0,0.1)"}`,
        fontFamily: fonts.body, fontSize: 15, color: colors.dark, background: "#fff",
        outline: "none", transition: "border-color 0.2s", ...style,
      }}
    />
  );
}

