// ── SCREEN 4: Home Feed ───────────────────────────────────────────────────────
function HomeScreen({ user, neighbourhood, onNav }) {
  const [posts, setPosts] = useState([
    { id: 1, author: "Finn", avatar: "🧑", text: "Hey guys, the electricity is out on Lake Street for the day.", time: "Now", likes: 3, fav: false },
    { id: 2, author: "Marie", avatar: "👩", text: "Hey guys, nice to be part of your community. I look forward to getting to know you all 😊", time: "2m", likes: 7, fav: false },
    { id: 3, author: "Jak", avatar: "🧔", text: "Could someone help me with my groceries this week?", time: "5m", likes: 2, fav: false, favor: true },
  ]);
  const [newPost, setNewPost] = useState("");
  const [activeTab, setActiveTab] = useState("newest");

  function addPost() {
    if (!newPost.trim()) return;
    setPosts([{ id: Date.now(), author: user.name || "You", avatar: "😊", text: newPost, time: "now", likes: 0, fav: false }, ...posts]);
    setNewPost("");
  }

  function grantFavor(id) {
    setPosts(posts.map(p => p.id === id ? { ...p, likes: p.likes + 10, fav: true } : p));
  }

  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column" }}>
      {/* Header */}
      <div style={{ padding: "12px 20px 0", background: "#fff", borderBottom: "1px solid rgba(0,0,0,0.06)" }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 12 }}>
          <h2 style={{ fontFamily: fonts.display, fontSize: 22, color: colors.blue }}>Announcements</h2>
          <span style={{ fontSize: 12, fontFamily: fonts.body, background: colors.bgBlue, borderRadius: 20, padding: "4px 10px", color: colors.blue, fontWeight: 600 }}>
            {neighbourhood.name}
          </span>
        </div>
        {/* Post composer */}
        <div style={{ display: "flex", gap: 10, marginBottom: 12 }}>
          <div style={{ flex: 1, background: colors.bgPink, borderRadius: 20, display: "flex", alignItems: "center", padding: "8px 14px", gap: 8 }}>
            <input value={newPost} onChange={e => setNewPost(e.target.value)} placeholder="Share something with your neighbours…" onKeyDown={e => e.key === "Enter" && addPost()}
              style={{ flex: 1, background: "none", border: "none", outline: "none", fontFamily: fonts.body, fontSize: 13, color: colors.dark }} />
          </div>
          <button onClick={addPost} style={{ background: colors.pink, border: "none", borderRadius: 20, width: 80, color: "#fff", fontFamily: fonts.body, fontWeight: 600, fontSize: 12, cursor: "pointer" }}>
            ✨ Ask for a favor
          </button>
        </div>
        {/* Tabs */}
        <div style={{ display: "flex", gap: 0, marginBottom: -1 }}>
          {["newest", "popular"].map(tab => (
            <button key={tab} onClick={() => setActiveTab(tab)} style={{
              background: "none", border: "none", borderBottom: `2px solid ${activeTab === tab ? colors.pink : "transparent"}`,
              padding: "6px 16px", fontFamily: fonts.body, fontWeight: 600, fontSize: 13,
              color: activeTab === tab ? colors.pink : "#999", cursor: "pointer",
            }}>
              {tab === "newest" ? "Newest messages" : "Popular"}
            </button>
          ))}
        </div>
      </div>
      {/* Feed */}
      <div style={{ flex: 1, overflowY: "auto", padding: "12px 20px", display: "flex", flexDirection: "column", gap: 12 }}>
        {posts.map((p, i) => (
          <div key={p.id} className="fadeUp" style={{ background: "#fff", borderRadius: 20, padding: "14px 16px", boxShadow: "0 2px 12px rgba(0,0,0,0.05)", animationDelay: `${i * 0.05}s` }}>
            <div style={{ display: "flex", gap: 10, marginBottom: 8 }}>
              <div style={{ width: 36, height: 36, borderRadius: "50%", background: colors.bgBlue, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 18, flexShrink: 0 }}>{p.avatar}</div>
              <div style={{ flex: 1 }}>
                <div style={{ display: "flex", justifyContent: "space-between" }}>
                  <span style={{ fontFamily: fonts.body, fontWeight: 700, fontSize: 13, color: colors.dark }}>{p.author}</span>
                  <span style={{ fontFamily: fonts.body, fontSize: 11, color: "#aaa" }}>{p.time}</span>
                </div>
                <p style={{ fontFamily: fonts.body, fontSize: 13, color: "#444", lineHeight: 1.5, marginTop: 4 }}>{p.text}</p>
              </div>
            </div>
            <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
              {p.favor && !p.fav && (
                <button onClick={() => grantFavor(p.id)} style={{ background: colors.bgGreen, border: "none", borderRadius: 20, padding: "5px 12px", fontFamily: fonts.body, fontSize: 12, fontWeight: 600, color: colors.green, cursor: "pointer" }}>
                  Grant favor +10 ⭐
                </button>
              )}
              {p.fav && <span style={{ fontFamily: fonts.body, fontSize: 12, color: colors.green }}>✓ Favor granted!</span>}
              <span style={{ marginLeft: "auto", fontFamily: fonts.body, fontSize: 12, color: "#aaa" }}>♡ {p.likes}</span>
            </div>
          </div>
        ))}
      </div>
      <BottomNav active="home" onNav={onNav} />
    </div>
  );
}

// ── SCREEN 5: Events ──────────────────────────────────────────────────────────
function EventsScreen({ user, onNav }) {
  const [activeTab, setActiveTab] = useState("Events");
  const [filter, setFilter] = useState("Upcoming");
  const tabs = ["Events", "Clubs", "Initiatives", "Locations"];
  const filters = ["Upcoming", "Today", "Tomorrow", "Weekend"];

  const events = [
    { id: 1, title: "Neighbourhood Potluck Dinner", desc: "Bring a dish to share — international cuisines welcome!", date: "Thu, Apr 30 · 14:41", location: "Vandal Community Hub", host: "Kyle", participants: 21, joined: false, aura: false, img: IMG_PEOPLE_POTLUCK },
    { id: 2, title: "Saturday Morning Yoga in the Park", desc: "Bring a mat and good vibes. Free for everyone.", date: "Sat, Apr 26 · 9:30", location: "Vondelpark · Lake entrance", host: "Mary", participants: 18, joined: false, aura: false, img: IMG_PEOPLE_GARDEN },
    { id: 3, title: "Book Club", desc: "We meet every other Tuesday to discuss a new book. Currently reading contemporary fiction.", date: "Sat, Apr 25 · 17:30", location: "Central Library", host: "Eva Janssen", participants: 9, joined: false, aura: false },
  ];

  const [eventList, setEventList] = useState(events);

  function joinEvent(id) {
    setEventList(eventList.map(e => e.id === id ? { ...e, joined: !e.joined, participants: e.joined ? e.participants - 1 : e.participants + 1 } : e));
  }

  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column" }}>
      {/* Hero illustration */}
      <div style={{ background: `linear-gradient(180deg, ${colors.bgGreen} 0%, ${colors.bgBlue} 100%)`, padding: "12px 20px 16px", overflow: "hidden", position: "relative", minHeight: 120 }}>
        <img src={IMG_PEOPLE_GARDEN} alt="" style={{ position: "absolute", right: 0, top: 0, height: "100%", objectFit: "cover", opacity: 0.5 }} />
        <h2 style={{ fontFamily: fonts.display, fontSize: 24, color: colors.blue, position: "relative", zIndex: 1 }}>Explore your community</h2>
        <div style={{ display: "flex", gap: 8, marginTop: 10, position: "relative", zIndex: 1, overflowX: "auto" }}>
          {filters.map(f => (
            <button key={f} onClick={() => setFilter(f)} style={{ background: filter === f ? colors.blue : "#fff", border: "none", borderRadius: 20, padding: "5px 14px", fontFamily: fonts.body, fontWeight: 600, fontSize: 12, color: filter === f ? "#fff" : colors.dark, cursor: "pointer", flexShrink: 0 }}>
              {f}
            </button>
          ))}
        </div>
      </div>
      {/* Tabs */}
      <div style={{ display: "flex", borderBottom: "1px solid rgba(0,0,0,0.08)", background: "#fff" }}>
        {tabs.map(t => (
          <button key={t} onClick={() => setActiveTab(t)} style={{ flex: 1, background: "none", border: "none", borderBottom: `2px solid ${activeTab === t ? colors.pink : "transparent"}`, padding: "12px 4px", fontFamily: fonts.body, fontWeight: 600, fontSize: 12, color: activeTab === t ? colors.pink : "#888", cursor: "pointer" }}>
            {t}
          </button>
        ))}
      </div>
      {/* Event list */}
      <div style={{ flex: 1, overflowY: "auto", padding: "12px 20px", display: "flex", flexDirection: "column", gap: 12 }}>
        {activeTab === "Events" && eventList.map((ev, i) => (
          <div key={ev.id} className="fadeUp" style={{ background: "#fff", borderRadius: 20, overflow: "hidden", boxShadow: "0 2px 12px rgba(0,0,0,0.06)", animationDelay: `${i * 0.07}s` }}>
            {ev.img && <img src={ev.img} alt="" style={{ width: "100%", height: 100, objectFit: "cover" }} />}
            <div style={{ padding: "12px 14px" }}>
              <div style={{ fontFamily: fonts.body, fontWeight: 700, fontSize: 14, color: colors.dark, marginBottom: 4 }}>{ev.title}</div>
              <div style={{ fontFamily: fonts.body, fontSize: 12, color: "#666", marginBottom: 8, lineHeight: 1.5 }}>{ev.desc}</div>
              <div style={{ fontFamily: fonts.body, fontSize: 11, color: colors.blue, marginBottom: 2 }}>📅 {ev.date}</div>
              <div style={{ fontFamily: fonts.body, fontSize: 11, color: "#888", marginBottom: 10 }}>📍 {ev.location}</div>
              <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between" }}>
                <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
                  <div style={{ width: 24, height: 24, borderRadius: "50%", background: colors.bgPink, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 12 }}>👤</div>
                  <span style={{ fontFamily: fonts.body, fontSize: 12, color: "#666" }}>by {ev.host}</span>
                  <span style={{ fontFamily: fonts.body, fontSize: 11, color: "#aaa" }}>{ev.participants}</span>
                </div>
                <button onClick={() => joinEvent(ev.id)} style={{ background: ev.joined ? colors.green : colors.blue, border: "none", borderRadius: 20, padding: "6px 16px", fontFamily: fonts.body, fontWeight: 600, fontSize: 12, color: "#fff", cursor: "pointer" }}>
                  {ev.joined ? "✓ Joined" : "Join"}
                </button>
              </div>
            </div>
          </div>
        ))}
        {activeTab !== "Events" && (
          <div style={{ textAlign: "center", padding: "40px 20px" }}>
            <img src={IMG_BLOB_SINGLE} alt="" style={{ width: 100, marginBottom: 16 }} />
            <p style={{ fontFamily: fonts.body, color: "#aaa", fontSize: 14 }}>{activeTab} coming soon!</p>
            <button style={{ marginTop: 12, background: colors.pink, border: "none", borderRadius: 20, padding: "8px 20px", fontFamily: fonts.body, fontWeight: 600, fontSize: 13, color: "#fff", cursor: "pointer" }}>
              + Start something new
            </button>
          </div>
        )}
      </div>
      <BottomNav active="events" onNav={onNav} />
    </div>
  );
}

