              <span style={{ fontFamily: fonts.body, fontWeight: 700, fontSize: 14, color: colors.dark }}>⭐ {s.label}</span>
              {s.count === 0 && <span style={{ fontFamily: fonts.body, fontSize: 11, color: "#aaa" }}>No saved {s.label.split(" ")[1].toLowerCase()} yet.</span>}
