// ── ROOT APP ──────────────────────────────────────────────────────────────────
export default function App() {
  const [screen, setScreen] = useState("welcome"); // welcome | signup | signin | neighbourhood | home | events | chat | market | profile
  const [user, setUser] = useState(null);
  const [neighbourhood, setNeighbourhood] = useState(null);

  function handleAuthSuccess(userData) {
    setUser(userData);
    setScreen("neighbourhood");
  }

  function handleNeighbourhood(n) {
    setNeighbourhood(n);
    setScreen("home");
  }

  function handleNav(tab) {
    setScreen(tab);
  }

  function handleLogout() {
    setUser(null);
    setNeighbourhood(null);
    setScreen("welcome");
  }

  const bgMap = {
    welcome: "#FAF9F6",
    signup: "#FAF9F6",
    signin: "#FAF9F6",
    neighbourhood: "#FAF9F6",
    home: "#F5F5F0",
    events: "#F5F5F0",
    chat: "#F5F5F0",
    market: "#F5F5F0",
    profile: "#F5F5F0",
  };

  return (
    <>
      <style>{globalStyle}</style>
      <PhoneShell bg={bgMap[screen] || "#FAF9F6"}>
        {screen === "welcome" && <WelcomeScreen onGoSignUp={() => setScreen("signup")} onGoSignIn={() => setScreen("signin")} />}
        {screen === "signup" && <SignUpScreen onBack={() => setScreen("welcome")} onSuccess={handleAuthSuccess} />}
        {screen === "signin" && <SignInScreen onBack={() => setScreen("welcome")} onSuccess={handleAuthSuccess} />}
        {screen === "neighbourhood" && <NeighbourhoodScreen onChoose={handleNeighbourhood} />}
        {screen === "home" && <HomeScreen user={user} neighbourhood={neighbourhood} onNav={handleNav} />}
        {screen === "events" && <EventsScreen user={user} onNav={handleNav} />}
        {screen === "chat" && <ComingSoonScreen label="Chat" icon="💬" img={IMG_BLOB_DUO} onNav={handleNav} activeNav="chat" />}
        {screen === "market" && <ComingSoonScreen label="Marketplace" icon="🛍️" img={IMG_BLOB_GROUP} onNav={handleNav} activeNav="market" />}
        {screen === "profile" && <ProfileScreen user={user} neighbourhood={neighbourhood} onNav={handleNav} onLogout={handleLogout} />}
      </PhoneShell>
    </>
  );
}
